dock.active:
my parent = MainRoot(part); my active = call notSechsEckTisch() and Size(ChildrenListOfTypeDeep(parent, 'basistraeger')) lt 2 and GetTypeName(parent) ne 'einsaeuliger_tisch';
				if (active) {
					my tb = FilterList(GetComponentListOfConnectionId(ConnectionId(part)), 'p', `not (IsSubTypeOf(p, 'tischblatt'));`)[0];
					active = RelativePartPos(part, tb)['x'] lt 0; 
					active = active and (Round(RelativePartRot(part, tb)['z'])%180) eq 0; 
				};
				active;

